  1→import React, { useState } from 'react';
  2→import { User, SMCContent } from '../types';
  3→import { smcService } from '../services/smc';
  4→import PageHeader from '../components/layout/PageHeader';
  5→import { ArrowLeft, FileText, HelpCircle, PenTool, Sparkles, Copy, Download, Check, Loader2, Layout, MessageSquare, BookOpen, Library, Clock, AlignLeft, Link as LinkIcon, Bot, Archive, ChevronRight, Award, Globe, ArrowRight, Eye } from 'lucide-react';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→  library: SMCContent[];
 12→  onAddToLibrary: (item: SMCContent) => void;
 13→  onNavigateToPublisher?: (data: { topic: string, url: string, brief: string }) => void;
 14→  onNavigateToDirectory?: () => void;
 15→}
 16→
 17→type ToolType = 'home' | 'fiche' | 'faq' | 'article';
 18→type Tab = 'studio' | 'library';
 19→
 20→const SMCStudio: React.FC<Props> = ({ onBack, user, onDeductCredits, library, onAddToLibrary, onNavigateToPublisher, onNavigateToDirectory }) => {
 21→  const [activeTab, setActiveTab] = useState<Tab>('studio');
 22→  const [currentTool, setCurrentTool] = useState<ToolType>('home');
 23→  const [result, setResult] = useState('');
 24→  const [isGenerating, setIsGenerating] = useState(false);
 25→  const [copied, setCopied] = useState(false);
 26→
 27→  // --- States pour l'outil Article (Flux Blog Optimizer) ---
 28→  const [articleStep, setArticleStep] = useState<'brief' | 'writing' | 'done'>('brief');
 29→  const [briefContent, setBriefContent] = useState('');
 30→  
 31→  // Form States
 32→  const [ficheData, setFicheData] = useState({ name: '', features: '' });
 33→  const [faqData, setFaqData] = useState({ topic: '', context: '' });
 34→  const [articleData, setArticleData] = useState({ title: '', url: '', tone: 'Professionnel' }); // URL & Tone used for Brief gen
 35→
 36→  const COSTS = {
 37→    fiche: 1,
 38→    faq: 1,
 39→    brief: 1, // Brief d'article
 40→    article: 3 // Rédaction complète
 41→  };
 42→
 43→  const handleCopy = (content: string) => {
 44→    navigator.clipboard.writeText(content);
 45→    setCopied(true);
 46→    setTimeout(() => setCopied(false), 2000);
 47→  };
 48→
 49→  const handleDownload = (filename: string, content: string) => {
 50→    const blob = new Blob([content], { type: 'text/markdown' });
 51→    const url = URL.createObjectURL(blob);
 52→    const a = document.createElement('a');
 53→    a.href = url;
 54→    a.download = filename;
 55→    document.body.appendChild(a);
 56→    a.click();
 57→    document.body.removeChild(a);
 58→    URL.revokeObjectURL(url);
 59→  };
 60→
 61→  const handleNavigateToPublisherAction = () => {
 62→    if (onNavigateToPublisher) {
 63→        onNavigateToPublisher({
 64→            topic: articleData.title,
 65→            url: articleData.url,
 66→            brief: briefContent // Le PublisherRequest se base sur le brief
 67→        });
 68→    }
 69→  };
 70→
 71→  const handleRestoreFromLibrary = (item: SMCContent) => {
 72→    // 1. Déterminer l'outil
 73→    let tool: ToolType = 'home';
 74→    if (item.type === 'fiche') tool = 'fiche';
 75→    else if (item.type === 'faq') tool = 'faq';
 76→    else if (item.type === 'article' || item.type === 'brief') tool = 'article';
 77→
 78→    setCurrentTool(tool);
 79→
 80→    // 2. Restaurer le contenu et l'état
 81→    if (item.type === 'article') {
 82→        setResult(item.content);
 83→        setArticleStep('done');
 84→        // Tentative de récupération du titre depuis "Article: Titre - Date"
 85→        const titleClean = item.title.split(' - ')[0].replace('Article: ', '').trim();
 86→        setArticleData(prev => ({ ...prev, title: titleClean }));
 87→        // Si possible, on pourrait essayer de retrouver le brief parent via meta, mais ici on affiche juste le résultat
 88→    } else if (item.type === 'brief') {
 89→        setBriefContent(item.content);
 90→        setArticleStep('writing');
 91→        const titleClean = item.title.split(' - ')[0].replace('Brief: ', '').trim();
 92→        setArticleData(prev => ({ ...prev, title: titleClean }));
 93→    } else {
 94→        setResult(item.content);
 95→        // Restauration contextuelle basique pour les formulaires
 96→        if (item.type === 'fiche') {
 97→             const nameClean = item.title.split(' - ')[0].replace('Fiche: ', '').trim();
 98→             setFicheData(prev => ({ ...prev, name: nameClean }));
 99→        }
100→        if (item.type === 'faq') {
101→             const topicClean = item.title.split(' - ')[0].replace('FAQ: ', '').trim();
102→             setFaqData(prev => ({ ...prev, topic: topicClean }));
103→        }
104→    }
105→
106→    // 3. Basculer vers l'onglet Studio
107→    setActiveTab('studio');
108→  };
109→
110→  // Generic generator for simple tools (Fiche, FAQ)
111→  const runSimpleGeneration = async (type: 'fiche' | 'faq', cost: number, generator: () => Promise<string>, titlePrefix: string) => {
112→    if (onDeductCredits(cost)) {
113→      setIsGenerating(true);
114→      setResult('');
115→      try {
116→        const content = await generator();
117→        setResult(content);
118→        
119→        // Save to Library
120→        const newItem: SMCContent = {
121→            id: `smc_${Date.now()}`,
122→            type,
123→            title: `${titlePrefix} - ${new Date().toLocaleTimeString()}`,
124→            content,
125→            timestamp: new Date().toISOString()
126→        };
127→        onAddToLibrary(newItem);
128→
129→      } catch (e) {
130→        console.error(e);
131→        alert("Une erreur est survenue.");
132→      } finally {
133→        setIsGenerating(false);
134→      }
135→    }
136→  };
137→
138→  // --- Article Generation Logic (2 Steps) ---
139→
140→  const handleGenerateBrief = async () => {
141→    if (!articleData.title && !articleData.url) {
142→        alert("Sujet ou URL requis.");
143→        return;
144→    }
145→
146→    if (onDeductCredits(COSTS.brief)) {
147→        setIsGenerating(true);
148→        try {
149→            const brief = await smcService.generateBrief(articleData.title, articleData.url);
150→            setBriefContent(brief);
151→            setArticleStep('writing'); // Move to step 2
152→            
153→            // Save Brief to Library
154→            onAddToLibrary({
155→                id: `brief_${Date.now()}`,
156→                type: 'brief',
157→                title: `Brief: ${articleData.title || 'Architecture Article'}`,
158→                content: brief,
159→                timestamp: new Date().toISOString()
160→            });
161→
162→        } catch (e) {
163→            console.error(e);
164→            alert("Erreur lors du brief.");
165→        } finally {
166→            setIsGenerating(false);
167→        }
168→    }
169→  };
170→
171→  const handleWriteFullArticle = async () => {
172→    if (onDeductCredits(COSTS.article)) {
173→        setIsGenerating(true);
174→        try {
175→            const article = await smcService.generateFullArticle(briefContent, articleData.title);
176→            setResult(article);
177→            setArticleStep('done'); // Move to step 3
178→
179→            // Save Article to Library
180→            onAddToLibrary({
181→                id: `art_${Date.now()}`,
182→                type: 'article',
183→                title: `Article: ${articleData.title || 'Rédaction Complète'}`,
184→                content: article,
185→                timestamp: new Date().toISOString(),
186→                meta: { briefId: `brief_${Date.now()}` } // Link to brief loosely
187→            });
188→
189→        } catch (e) {
190→            console.error(e);
191→            alert("Erreur lors de la rédaction.");
192→        } finally {
193→            setIsGenerating(false);
194→        }
195→    }
196→  };
197→
198→  const renderHome = () => (
199→    <div className="space-y-8 page-enter">
200→      <div className="text-center space-y-4">
201→        <h1 className="text-4xl font-bold text-white">SMC <span className="gradient-text">Studio</span></h1>
202→        <p className="text-gray-400 max-w-xl mx-auto">
203→          Smart Marketing Content : Votre usine de production de contenu optimisé pour les Answer Engines.
204→        </p>
205→      </div>
206→
207→      <div className="grid md:grid-cols-3 gap-6 w-full">
208→        {/* Card Fiche */}
209→        <button
210→          onClick={() => setCurrentTool('fiche')}
211→          className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-8 hover:border-blue-500/50 hover:bg-white/[0.03] transition-all group text-left relative overflow-hidden"
212→        >
213→          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
214→            <Layout size={80} />
215→          </div>
216→          <div className="w-12 h-12 rounded-xl bg-blue-500/20 flex items-center justify-center text-blue-400 mb-6 group-hover:scale-110 transition-transform">
217→            <FileText size={24} />
218→          </div>
219→          <h3 className="text-xl font-bold text-white mb-2">Fiche Produit</h3>
220→          <p className="text-sm text-gray-400 mb-6">Générez des fiches techniques structurées et vendeuses.</p>
221→          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-blue-500/10 text-blue-400 text-xs font-bold border border-blue-500/20">
222→            <Sparkles size={10} /> 1 Crédit
223→          </div>
224→        </button>
225→
226→        {/* Card FAQ */}
227→        <button
228→          onClick={() => setCurrentTool('faq')}
229→          className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-8 hover:border-purple-500/50 hover:bg-white/[0.03] transition-all group text-left relative overflow-hidden"
230→        >
231→          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
232→            <MessageSquare size={80} />
233→          </div>
234→          <div className="w-12 h-12 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 mb-6 group-hover:scale-110 transition-transform">
235→            <HelpCircle size={24} />
236→          </div>
237→          <h3 className="text-xl font-bold text-white mb-2">Générateur FAQ</h3>
238→          <p className="text-sm text-gray-400 mb-6">Créez des questions/réponses pertinentes pour rassurer vos clients.</p>
239→          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-500/10 text-purple-400 text-xs font-bold border border-purple-500/20">
240→            <Sparkles size={10} /> 1 Crédit
241→          </div>
242→        </button>
243→
244→        {/* Card Article */}
245→        <button
246→          onClick={() => setCurrentTool('article')}
247→          className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-8 hover:border-purple-500/50 hover:bg-white/[0.03] transition-all group text-left relative overflow-hidden"
248→        >
249→          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
250→            <BookOpen size={80} />
251→          </div>
252→          <div className="w-12 h-12 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 mb-6 group-hover:scale-110 transition-transform">
253→            <PenTool size={24} />
254→          </div>
255→          <h3 className="text-xl font-bold text-white mb-2">Rédaction Article</h3>
256→          <p className="text-sm text-gray-400 mb-6">Workflow complet : Architecture (Brief) puis Rédaction AEO.</p>
257→          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-500/10 text-purple-400 text-xs font-bold border border-purple-500/20">
258→            <Sparkles size={10} /> 1 + 3 Crédits
259→          </div>
260→        </button>
261→      </div>
262→    </div>
263→  );
264→
265→  const renderToolArchives = (tool: ToolType) => {
266→    const archives = library.filter(item => {
267→        if (tool === 'article') return item.type === 'article' || item.type === 'brief';
268→        return item.type === tool;
269→    });
270→
271→    if (archives.length === 0) return null;
272→
273→    return (
274→        <div className="border-t border-white/[0.06] pt-10 animate-in fade-in slide-in-from-bottom-8">
275→            <div className="flex items-center justify-between mb-6">
276→                <h3 className="text-xl font-serif font-bold text-white flex items-center gap-2">
277→                    <Archive size={20} className="text-gray-400" /> 
278→                    Archives {tool === 'fiche' ? 'Fiches Produits' : tool === 'faq' ? 'FAQs' : 'Articles & Briefs'}
279→                </h3>
280→                <span className="text-xs text-gray-500 bg-purple-500/5 px-2 py-1 rounded-full">{archives.length} fichiers</span>
281→            </div>
282→
283→            <div className="grid md:grid-cols-3 gap-6">
284→                {archives.map((item) => (
285→                    <div key={item.id} className="glass-panel p-5 rounded-xl border border-white/[0.06] hover:border-primary/30 transition-all group flex flex-col">
286→                        <div className="flex justify-between items-start mb-3">
287→                            <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider 
288→                                ${item.type === 'article' ? 'bg-purple-400/10 text-purple-300 border border-purple-400/20' : 
289→                                  item.type === 'brief' ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 
290→                                  'bg-blue-500/10 text-blue-400 border border-blue-500/20'}`}>
291→                                {item.type.toUpperCase()}
292→                            </span>
293→                            <span className="text-xs text-gray-500 flex items-center gap-1">
294→                                <Clock size={10} /> {new Date(item.timestamp).toLocaleDateString()}
295→                            </span>
296→                        </div>
297→                        
298→                        <h4 className="font-bold text-white mb-2 line-clamp-2 min-h-[3rem] text-sm">{item.title}</h4>
299→                        
300→                        <div className="bg-[#050208] p-3 rounded border border-[var(--border-subtle)] mb-4 flex-1 overflow-hidden relative h-24">
301→                            <p className="text-[10px] text-gray-500 font-mono line-clamp-4 leading-relaxed">{item.content}</p>
302→                            <div className="absolute bottom-0 left-0 w-full h-8 bg-gradient-to-t from-[#050208] to-transparent"></div>
303→                        </div>
304→
305→                        <div className="flex gap-2 pt-2 border-t border-[var(--border-subtle)]">
306→                            <button 
307→                                onClick={() => handleRestoreFromLibrary(item)}
308→                                className="flex-1 py-1.5 bg-primary/10 hover:bg-primary/20 rounded text-[10px] font-bold text-primary transition-colors flex items-center justify-center gap-1"
309→                            >
310→                                <Eye size={10} /> Ouvrir
311→                            </button>
312→                            <button 
313→                                onClick={() => handleCopy(item.content)}
314→                                className="flex-1 py-1.5 bg-purple-500/5 hover:bg-white/10 rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
315→                            >
316→                                <Copy size={10} /> Copier
317→                            </button>
318→                        </div>
319→                    </div>
320→                ))}
321→            </div>
322→        </div>
323→    );
324→  };
325→
326→  const renderTool = () => {
327→    let title = '', color = '', icon = null;
328→    
329→    switch(currentTool) {
330→      case 'fiche': title = 'Fiche Produit'; color = 'text-blue-400'; icon = <FileText />; break;
331→      case 'faq': title = 'Générateur FAQ'; color = 'text-purple-400'; icon = <HelpCircle />; break;
332→      case 'article': title = 'Rédaction Article'; color = 'text-purple-400'; icon = <PenTool />; break;
333→    }
334→
335→    // Contenu à afficher dans la fenêtre de droite
336→    const displayContent = currentTool === 'article' 
337→        ? (articleStep === 'done' ? result : briefContent) 
338→        : result;
339→
340→    return (
341→      <div className="flex flex-col gap-12 animate-in slide-in-from-right duration-300">
342→        <div className="grid lg:grid-cols-12 gap-8 h-full min-h-[600px]">
343→          
344→          {/* Left: Input Form */}
345→          <div className="lg:col-span-4 space-y-6">
346→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
347→              <div className="flex items-center gap-3 mb-6">
348→                <div className={`p-2 rounded-lg bg-purple-500/10 ${color}`}>{icon}</div>
349→                <h2 className="text-xl font-bold text-white">{title}</h2>
350→              </div>
351→
352→              {currentTool === 'fiche' && (
353→                <div className="space-y-4">
354→                  <div>
355→                    <label className="text-sm text-gray-400 block mb-2">Nom du produit / service</label>
356→                    <input
357→                      type="text"
358→                      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl p-3 text-white focus:border-blue-500/50 outline-none"
359→                      placeholder="Ex: SuperVacuum 3000"
360→                      value={ficheData.name}
361→                      onChange={(e) => setFicheData({...ficheData, name: e.target.value})}
362→                    />
363→                  </div>
364→                  <div>
365→                    <label className="text-sm text-gray-400 block mb-2">Caractéristiques / Notes en vrac</label>
366→                    <textarea
367→                      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl p-3 text-white focus:border-blue-500/50 outline-none h-40 resize-none"
368→                      placeholder="- Aspiration 200W&#10;- Silencieux&#10;- Batterie 1h"
369→                      value={ficheData.features}
370→                      onChange={(e) => setFicheData({...ficheData, features: e.target.value})}
371→                    />
372→                  </div>
373→                  <button
374→                    onClick={() => runSimpleGeneration('fiche', COSTS.fiche, () => smcService.generateFiche(ficheData.name, ficheData.features), `Fiche: ${ficheData.name}`)}
375→                    disabled={isGenerating || !ficheData.name}
376→                    className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
377→                  >
378→                    {isGenerating ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
379→                    Générer ({COSTS.fiche} Crédit)
380→                  </button>
381→                </div>
382→              )}
383→
384→              {currentTool === 'faq' && (
385→                <div className="space-y-4">
386→                  <div>
387→                    <label className="text-sm text-gray-400 block mb-2">Sujet Principal</label>
388→                    <input
389→                      type="text"
390→                      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none"
391→                      placeholder="Ex: Politique de retour"
392→                      value={faqData.topic}
393→                      onChange={(e) => setFaqData({...faqData, topic: e.target.value})}
394→                    />
395→                  </div>
396→                  <div>
397→                    <label className="text-sm text-gray-400 block mb-2">Contexte / Éléments à inclure</label>
398→                    <textarea
399→                      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none h-40 resize-none"
400→                      placeholder="30 jours pour changer d'avis. Frais de retour gratuits si défectueux."
401→                      value={faqData.context}
402→                      onChange={(e) => setFaqData({...faqData, context: e.target.value})}
403→                    />
404→                  </div>
405→                  <button 
406→                    onClick={() => runSimpleGeneration('faq', COSTS.faq, () => smcService.generateFAQ(faqData.topic, faqData.context), `FAQ: ${faqData.topic}`)}
407→                    disabled={isGenerating || !faqData.topic}
408→                    className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
409→                  >
410→                    {isGenerating ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
411→                    Générer ({COSTS.faq} Crédit)
412→                  </button>
413→                </div>
414→              )}
415→
416→              {/* INTEGRATED BLOG OPTIMIZER FLOW */}
417→              {currentTool === 'article' && (
418→                <div className="space-y-6">
419→                  {/* Steps Indicator */}
420→                  <div className="flex items-center gap-2 text-xs mb-4">
421→                      <span className={`px-2 py-1 rounded ${articleStep === 'brief' ? 'bg-purple-500 text-white' : 'bg-white/10 text-gray-500'}`}>1. Brief</span>
422→                      <ChevronRight size={12} className="text-[var(--text-disabled)]"/>
423→                      <span className={`px-2 py-1 rounded ${articleStep === 'writing' ? 'bg-purple-500 text-white' : 'bg-white/10 text-gray-500'}`}>2. Validation</span>
424→                      <ChevronRight size={12} className="text-[var(--text-disabled)]"/>
425→                      <span className={`px-2 py-1 rounded ${articleStep === 'done' ? 'bg-purple-400 text-white' : 'bg-white/10 text-gray-500'}`}>3. Article</span>
426→                  </div>
427→
428→                  <div className="space-y-4">
429→                      <div>
430→                          <label className="text-sm text-gray-400 block mb-2 flex items-center gap-2">
431→                              <AlignLeft size={16} /> Sujet / Mot-clé
432→                          </label>
433→                          <input
434→                              type="text"
435→                              className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none"
436→                              placeholder="Ex: Avantages AEO"
437→                              value={articleData.title}
438→                              onChange={(e) => setArticleData({...articleData, title: e.target.value})}
439→                              disabled={articleStep !== 'brief'}
440→                          />
441→                      </div>
442→                      <div>
443→                          <label className="text-sm text-gray-400 block mb-2 flex items-center gap-2">
444→                              <LinkIcon size={16} /> URL Source (Optionnel)
445→                          </label>
446→                          <input
447→                              type="url"
448→                              className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none"
449→                              placeholder="https://..."
450→                              value={articleData.url}
451→                              onChange={(e) => setArticleData({...articleData, url: e.target.value})}
452→                              disabled={articleStep !== 'brief'}
453→                          />
454→                      </div>
455→
456→                      {articleStep === 'brief' && (
457→                          <button 
458→                              onClick={handleGenerateBrief}
459→                              disabled={isGenerating || (!articleData.title && !articleData.url)}
460→                              className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 disabled:opacity-50"
461→                          >
462→                              {isGenerating ? <Loader2 className="animate-spin" /> : <FileText size={18} />}
463→                              Générer le Brief ({COSTS.brief} Crédit)
464→                          </button>
465→                      )}
466→
467→                      {articleStep === 'writing' && (
468→                          <div className="space-y-4 pt-2 border-t border-[var(--border-subtle)] animate-in fade-in">
469→                              <p className="text-xs text-gray-400">Le brief est prêt. Vous pouvez maintenant lancer la rédaction complète.</p>
470→                              <button 
471→                                  onClick={handleWriteFullArticle}
472→                                  disabled={isGenerating}
473→                                  className="w-full py-3 btn-gradient !rounded-full transition-all flex items-center justify-center gap-2 shadow-lg shadow-purple-500/20"
474→                              >
475→                                  {isGenerating ? <Loader2 className="animate-spin" /> : <PenTool size={18} />}
