 34→  // Pré-remplissage basé sur l'historique
 35→  useEffect(() => {
 36→    if (history.length > 0) {
 37→      const latest = history[0];
 38→      const urlObj = new URL(latest.url);
 39→      const hostname = urlObj.hostname;
