 31→    const processUrl = (analysis: AnalysisResult | undefined) => {
 32→        if (!analysis) {
 33→            // Mode Demo / Fallback
 34→            const demoUrl = "https://monsite-wordpress.com";
 35→            setCurrentContent(parseCurrentRobotsTxt(demoUrl));
 36→            setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
 37→            setPlatformName(getDetectedPlatformName(demoUrl));
 38→            setIsUnlocked(false);
 39→            return;
 40→        }
 41→
 42→        const url = analysis.url;
 43→        setCurrentContent(parseCurrentRobotsTxt(url));
 44→        setPlatformName(getDetectedPlatformName(url));
 45→
 46→        // Check if previously unlocked/saved in history
 47→        if (analysis.robotsTxtData && analysis.robotsTxtData.isUnlocked) {
 48→            setOptimizedContent(analysis.robotsTxtData.content);
 49→            setIsUnlocked(true);
 50→        } else {
 51→            // Fresh generation (locked)
 52→            setOptimizedContent(generateOptimizedRobotsTxt(url));
 53→            setIsUnlocked(false);
 54→        }
 55→    };
 56→
 57→    if (history.length > 0) {
 58→      processUrl(history[selectedAnalysisIndex]);
